export async function handleBuildingEnter(request: Request, env: Env): Promise<Response> {
  const authResult = await requireAuth(request, env);
  if (authResult instanceof Response) return authResult;

  const rateCheck = await checkRateLimit(authResult.sub, 'building_enter', env);
  if (!rateCheck.allowed) return rateLimitResponse(rateCheck.retryAfter!);

  const body = await request.json() as { building_id?: string; building_name?: string; building_type?: string; enter_home?: boolean };

  // Need at least one identifier (enter_home is a shortcut to enter own house)
  if (!body.building_id && !body.building_name && !body.building_type && !body.enter_home) {
    return new Response(JSON.stringify({ success: false, error: 'Provide building_id, building_name, building_type, or enter_home: true' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  if (body.building_id && !isValidUUID(body.building_id)) {
    return new Response(JSON.stringify({ success: false, error: 'Invalid building ID format' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  const supabase = createSupabaseClient(env);

  // Get bot's current zone for scoped lookup
  const { data: botData } = await supabase
    .from('bots')
    .select('current_zone_id, x, y')
    .eq('id', authResult.sub)
    .single();

  if (!botData) {
    return new Response(JSON.stringify({ success: false, error: 'Bot not found' }),
      { status: 404, headers: { 'Content-Type': 'application/json' } });
  }

  // Resolve building — by ID, name, type, or enter_home (scoped to bot's zone)
  let building: { id: string; type: string; zone_id: number; name?: string; x?: number; y?: number; owner_bot_id?: string } | null = null;

  // enter_home: resolve bot's own house (any zone, no proximity check)
  if (body.enter_home) {
    const { data } = await supabase
      .from('buildings')
      .select('id, type, zone_id, name, x, y, owner_bot_id')
      .eq('owner_bot_id', authResult.sub)
      .eq('type', 'house')
      .limit(1)
      .maybeSingle();
    building = data;
    if (!building) {
      return new Response(JSON.stringify({
        success: false, error: 'You do not have a home yet',
        hint: 'Homes are auto-created on registration. Contact support if this is unexpected.',
      }), { status: 404, headers: { 'Content-Type': 'application/json' } });
    }
  } else if (body.building_id) {
    const { data } = await supabase
      .from('buildings')
      .select('id, type, zone_id, name, x, y, owner_bot_id')
      .eq('id', body.building_id)
      .single();
    building = data;

