  building = data;
} else if (body.building_name) {
  // Escape ILIKE wildcards to prevent matching all buildings with "%"
  const safeName = body.building_name.replace(/[%_\\]/g, '\\$&');
  const { data } = await supabase
    .from('buildings')
    .select('id, type, zone_id, name, x, y, owner_bot_id')
    .eq('zone_id', botData.current_zone_id)
    .ilike('name', safeName)
    .limit(1)
    .maybeSingle();
  building = data;
} else if (body.building_type) {
  const { data } = await supabase
    .from('buildings')
    .select('id, type, zone_id, name, x, y, owner_bot_id')
    .eq('zone_id', botData.current_zone_id)
    .eq('type', body.building_type)
    .limit(1)
    .maybeSingle();
  building = data;
}

if (!building) {
  // Provide available buildings in the zone so agent can pick
  const { data: available } = await supabase
    .from('buildings')
    .select('name, type')
    .eq('zone_id', botData.current_zone_id);
  return new Response(JSON.stringify({
    success: false, error: 'Building not found in your zone',
    available_buildings: (available || []).map(b => ({ name: b.name, type: b.type })),
  }), { status: 404, headers: { 'Content-Type': 'application/json' } });
}

// Skip proximity check for house owners (they can enter from anywhere via enter_home)
const isOwner = building.owner_bot_id === authResult.sub;

// Hard proximity enforcement — bot must walk to the building entrance before entering.
// Uses entrance waypoint coords (not building center, which is inside the footprint).

